    70→export function updateIgnoredSettings(targetContent: string, sourceContent: string, ignoredSettings: string[], formattingOptions: FormattingOptions): string {
    71→	if (ignoredSettings.length) {
    72→		const sourceTree = parseSettings(sourceContent);
    73→		const source = parse(sourceContent) || {};
    74→		const target = parse(targetContent);
    75→		if (!target) {
    76→			return targetContent;
    77→		}
    78→		const settingsToAdd: INode[] = [];
    79→		for (const key of ignoredSettings) {
    80→			const sourceValue = source[key];
    81→			const targetValue = target[key];
    82→
    83→			// Remove in target
    84→			if (sourceValue === undefined) {
    85→				targetContent = contentUtil.edit(targetContent, [key], undefined, formattingOptions);
    86→			}
    87→
    88→			// Update in target
    89→			else if (targetValue !== undefined) {
    90→				targetContent = contentUtil.edit(targetContent, [key], sourceValue, formattingOptions);
    91→			}
    92→
    93→			else {
    94→				settingsToAdd.push(findSettingNode(key, sourceTree)!);
    95→			}
    96→		}
    97→
    98→		settingsToAdd.sort((a, b) => a.startOffset - b.startOffset);
    99→		settingsToAdd.forEach(s => targetContent = addSetting(s.setting!.key, sourceContent, targetContent, formattingOptions));
   100→	}
   101→	return targetContent;
   102→}
