   104→export function merge(originalLocalContent: string, originalRemoteContent: string, baseContent: string | null, ignoredSettings: string[], resolvedConflicts: { key: string; value: any | undefined }[], formattingOptions: FormattingOptions): IMergeResult {
   105→
   106→	const localContentWithoutIgnoredSettings = updateIgnoredSettings(originalLocalContent, originalRemoteContent, ignoredSettings, formattingOptions);
   107→	const localForwarded = baseContent !== localContentWithoutIgnoredSettings;
   108→	const remoteForwarded = baseContent !== originalRemoteContent;
   109→
   110→	/* no changes */
   111→	if (!localForwarded && !remoteForwarded) {
   112→		return { conflictsSettings: [], localContent: null, remoteContent: null, hasConflicts: false };
   113→	}
   114→
   115→	/* local has changed and remote has not */
   116→	if (localForwarded && !remoteForwarded) {
   117→		return { conflictsSettings: [], localContent: null, remoteContent: localContentWithoutIgnoredSettings, hasConflicts: false };
   118→	}
   119→
   120→	/* remote has changed and local has not */
   121→	if (remoteForwarded && !localForwarded) {
   122→		return { conflictsSettings: [], localContent: updateIgnoredSettings(originalRemoteContent, originalLocalContent, ignoredSettings, formattingOptions), remoteContent: null, hasConflicts: false };
   123→	}
   124→
   125→	/* local is empty and not synced before */
   126→	if (baseContent === null && isEmpty(originalLocalContent)) {
   127→		const localContent = areSame(originalLocalContent, originalRemoteContent, ignoredSettings) ? null : updateIgnoredSettings(originalRemoteContent, originalLocalContent, ignoredSettings, formattingOptions);
   128→		return { conflictsSettings: [], localContent, remoteContent: null, hasConflicts: false };
   129→	}
   130→
   131→	/* remote and local has changed */
   132→	let localContent = originalLocalContent;
   133→	let remoteContent = originalRemoteContent;
   134→	const local = parse(originalLocalContent);
   135→	const remote = parse(originalRemoteContent);
   136→	const base = baseContent ? parse(baseContent) : null;
   137→
   138→	const ignored = ignoredSettings.reduce((set, key) => { set.add(key); return set; }, new Set<string>());
   139→	const localToRemote = compare(local, remote, ignored);
   140→	const baseToLocal = compare(base, local, ignored);
   141→	const baseToRemote = compare(base, remote, ignored);
   142→
   143→	const conflicts: Map<string, IConflictSetting> = new Map<string, IConflictSetting>();
   144→	const handledConflicts: Set<string> = new Set<string>();
   145→	const handleConflict = (conflictKey: string): void => {
   146→		handledConflicts.add(conflictKey);
   147→		const resolvedConflict = resolvedConflicts.filter(({ key }) => key === conflictKey)[0];
   148→		if (resolvedConflict) {
   149→			localContent = contentUtil.edit(localContent, [conflictKey], resolvedConflict.value, formattingOptions);
   150→			remoteContent = contentUtil.edit(remoteContent, [conflictKey], resolvedConflict.value, formattingOptions);
   151→		} else {
   152→			conflicts.set(conflictKey, { key: conflictKey, localValue: local[conflictKey], remoteValue: remote[conflictKey] });
   153→		}
   154→	};
   155→
   156→	// Removed settings in Local
   157→	for (const key of baseToLocal.removed.values()) {
   158→		// Conflict - Got updated in remote.
   159→		if (baseToRemote.updated.has(key)) {
   160→			handleConflict(key);
   161→		}
   162→		// Also remove in remote
   163→		else {
   164→			remoteContent = contentUtil.edit(remoteContent, [key], undefined, formattingOptions);
   165→		}
   166→	}
   167→
   168→	// Removed settings in Remote
   169→	for (const key of baseToRemote.removed.values()) {
   170→		if (handledConflicts.has(key)) {
   171→			continue;
   172→		}
   173→		// Conflict - Got updated in local
   174→		if (baseToLocal.updated.has(key)) {
   175→			handleConflict(key);
   176→		}
   177→		// Also remove in locals
   178→		else {
   179→			localContent = contentUtil.edit(localContent, [key], undefined, formattingOptions);
   180→		}
   181→	}
   182→
   183→	// Updated settings in Local
   184→	for (const key of baseToLocal.updated.values()) {
   185→		if (handledConflicts.has(key)) {
   186→			continue;
   187→		}
   188→		// Got updated in remote
   189→		if (baseToRemote.updated.has(key)) {
   190→			// Has different value
   191→			if (localToRemote.updated.has(key)) {
   192→				handleConflict(key);
   193→			}
   194→		} else {
   195→			remoteContent = contentUtil.edit(remoteContent, [key], local[key], formattingOptions);
   196→		}
   197→	}
   198→
   199→	// Updated settings in Remote
   200→	for (const key of baseToRemote.updated.values()) {
   201→		if (handledConflicts.has(key)) {
   202→			continue;
   203→		}
   204→		// Got updated in local
   205→		if (baseToLocal.updated.has(key)) {
   206→			// Has different value
   207→			if (localToRemote.updated.has(key)) {
   208→				handleConflict(key);
   209→			}
   210→		} else {
   211→			localContent = contentUtil.edit(localContent, [key], remote[key], formattingOptions);
   212→		}
   213→	}
   214→
   215→	// Added settings in Local
   216→	for (const key of baseToLocal.added.values()) {
   217→		if (handledConflicts.has(key)) {
   218→			continue;
   219→		}
   220→		// Got added in remote
   221→		if (baseToRemote.added.has(key)) {
   222→			// Has different value
   223→			if (localToRemote.updated.has(key)) {
   224→				handleConflict(key);
   225→			}
   226→		} else {
   227→			remoteContent = addSetting(key, localContent, remoteContent, formattingOptions);
   228→		}
   229→	}
   230→
   231→	// Added settings in remote
   232→	for (const key of baseToRemote.added.values()) {
   233→		if (handledConflicts.has(key)) {
   234→			continue;
   235→		}
   236→		// Got added in local
   237→		if (baseToLocal.added.has(key)) {
   238→			// Has different value
   239→			if (localToRemote.updated.has(key)) {
   240→				handleConflict(key);
   241→			}
   242→		} else {
   243→			localContent = addSetting(key, remoteContent, localContent, formattingOptions);
   244→		}
   245→	}
   246→
   247→	const hasConflicts = conflicts.size > 0 || !areSame(localContent, remoteContent, ignoredSettings);
   248→	const hasLocalChanged = hasConflicts || !areSame(localContent, originalLocalContent, []);
   249→	const hasRemoteChanged = hasConflicts || !areSame(remoteContent, originalRemoteContent, []);
   250→	return { localContent: hasLocalChanged ? localContent : null, remoteContent: hasRemoteChanged ? remoteContent : null, conflictsSettings: [...conflicts.values()], hasConflicts };
   251→}
   252→
   253→function areSame(localContent: string, remoteContent: string, ignoredSettings: string[]): boolean {
   254→	if (localContent === remoteContent) {
   255→		return true;
   256→	}
   257→
   258→	const local = parse(localContent);
   259→	const remote = parse(remoteContent);
   260→	const ignored = ignoredSettings.reduce((set, key) => { set.add(key); return set; }, new Set<string>());
   261→	const localTree = parseSettings(localContent).filter(node => !(node.setting && ignored.has(node.setting.key)));
   262→	const remoteTree = parseSettings(remoteContent).filter(node => !(node.setting && ignored.has(node.setting.key)));
   263→
   264→	if (localTree.length !== remoteTree.length) {
   265→		return false;
   266→	}
   267→
   268→	for (let index = 0; index < localTree.length; index++) {
   269→		const localNode = localTree[index];
   270→		const remoteNode = remoteTree[index];
   271→		if (localNode.setting && remoteNode.setting) {
   272→			if (localNode.setting.key !== remoteNode.setting.key) {
   273→				return false;
   274→			}
   275→			if (!objects.equals(local[localNode.setting.key], remote[localNode.setting.key])) {
   276→				return false;
   277→			}
   278→		} else if (!localNode.setting && !remoteNode.setting) {
   279→			if (localNode.value !== remoteNode.value) {
   280→				return false;
   281→			}
   282→		} else {
   283→			return false;
   284→		}
   285→	}
   286→
   287→	return true;
   288→}
   289→
   290→export function isEmpty(content: string): boolean {
   291→	if (content) {
   292→		const nodes = parseSettings(content);
   293→		return nodes.length === 0;
   294→	}
   295→	return true;
   296→}
   297→
   298→function compare(from: IStringDictionary<any> | null, to: IStringDictionary<any>, ignored: Set<string>): { added: Set<string>; removed: Set<string>; updated: Set<string> } {
   299→	const fromKeys = from ? Object.keys(from).filter(key => !ignored.has(key)) : [];
   300→	const toKeys = Object.keys(to).filter(key => !ignored.has(key));
   301→	const added = toKeys.filter(key => !fromKeys.includes(key)).reduce((r, key) => { r.add(key); return r; }, new Set<string>());
   302→	const removed = fromKeys.filter(key => !toKeys.includes(key)).reduce((r, key) => { r.add(key); return r; }, new Set<string>());
   303→	const updated: Set<string> = new Set<string>();
   304→
   305→	if (from) {
   306→		for (const key of fromKeys) {
   307→			if (removed.has(key)) {
   308→				continue;
   309→			}
   310→			const value1 = from[key];
   311→			const value2 = to[key];
   312→			if (!objects.equals(value1, value2)) {
   313→				updated.add(key);
   314→			}
   315→		}
   316→	}
   317→
   318→	return { added, removed, updated };
   319→}
   320→
   321→export function addSetting(key: string, sourceContent: string, targetContent: string, formattingOptions: FormattingOptions): string {
   322→	const source = parse(sourceContent);
   323→	const sourceTree = parseSettings(sourceContent);
   324→	const targetTree = parseSettings(targetContent);
   325→	const insertLocation = getInsertLocation(key, sourceTree, targetTree);
   326→	return insertAtLocation(targetContent, key, source[key], insertLocation, targetTree, formattingOptions);
   327→}
   328→
   329→interface InsertLocation {
   330→	index: number;
   331→	insertAfter: boolean;
   332→}
   333→
   334→function getInsertLocation(key: string, sourceTree: INode[], targetTree: INode[]): InsertLocation {
   335→
   336→	const sourceNodeIndex = sourceTree.findIndex(node => node.setting?.key === key);
   337→
   338→	const sourcePreviousNode: INode = sourceTree[sourceNodeIndex - 1];
   339→	if (sourcePreviousNode) {
   340→		/*
   341→			Previous node in source is a setting.
   342→			Find the same setting in the target.
   343→			Insert it after that setting
   344→		*/
   345→		if (sourcePreviousNode.setting) {
   346→			const targetPreviousSetting = findSettingNode(sourcePreviousNode.setting.key, targetTree);
   347→			if (targetPreviousSetting) {
   348→				/* Insert after target's previous setting */
   349→				return { index: targetTree.indexOf(targetPreviousSetting), insertAfter: true };
   350→			}
   351→		}
   352→		/* Previous node in source is a comment */
   353→		else {
   354→			const sourcePreviousSettingNode = findPreviousSettingNode(sourceNodeIndex, sourceTree);
   355→			/*
   356→				Source has a setting defined before the setting to be added.
   357→				Find the same previous setting in the target.
   358→				If found, insert before its next setting so that comments are retrieved.
   359→				Otherwise, insert at the end.
   360→			*/
   361→			if (sourcePreviousSettingNode) {
   362→				const targetPreviousSetting = findSettingNode(sourcePreviousSettingNode.setting!.key, targetTree);
   363→				if (targetPreviousSetting) {
   364→					const targetNextSetting = findNextSettingNode(targetTree.indexOf(targetPreviousSetting), targetTree);
   365→					const sourceCommentNodes = findNodesBetween(sourceTree, sourcePreviousSettingNode, sourceTree[sourceNodeIndex]);
   366→					if (targetNextSetting) {
   367→						const targetCommentNodes = findNodesBetween(targetTree, targetPreviousSetting, targetNextSetting);
   368→						const targetCommentNode = findLastMatchingTargetCommentNode(sourceCommentNodes, targetCommentNodes);
   369→						if (targetCommentNode) {
   370→							return { index: targetTree.indexOf(targetCommentNode), insertAfter: true }; /* Insert after comment */
   371→						} else {
   372→							return { index: targetTree.indexOf(targetNextSetting), insertAfter: false }; /* Insert before target next setting */
   373→						}
   374→					} else {
   375→						const targetCommentNodes = findNodesBetween(targetTree, targetPreviousSetting, targetTree[targetTree.length - 1]);
   376→						const targetCommentNode = findLastMatchingTargetCommentNode(sourceCommentNodes, targetCommentNodes);
   377→						if (targetCommentNode) {
   378→							return { index: targetTree.indexOf(targetCommentNode), insertAfter: true }; /* Insert after comment */
   379→						} else {
   380→							return { index: targetTree.length - 1, insertAfter: true }; /* Insert at the end */
   381→						}
   382→					}
   383→				}
   384→			}
   385→		}
   386→
   387→		const sourceNextNode = sourceTree[sourceNodeIndex + 1];
   388→		if (sourceNextNode) {
   389→			/*
   390→				Next node in source is a setting.
   391→				Find the same setting in the target.
   392→				Insert it before that setting
   393→			*/
   394→			if (sourceNextNode.setting) {
   395→				const targetNextSetting = findSettingNode(sourceNextNode.setting.key, targetTree);
   396→				if (targetNextSetting) {
   397→					/* Insert before target's next setting */
   398→					return { index: targetTree.indexOf(targetNextSetting), insertAfter: false };
   399→				}
   400→			}
   401→			/* Next node in source is a comment */
   402→			else {
   403→				const sourceNextSettingNode = findNextSettingNode(sourceNodeIndex, sourceTree);
   404→				/*
   405→					Source has a setting defined after the setting to be added.
   406→					Find the same next setting in the target.
   407→					If found, insert after its previous setting so that comments are retrieved.
   408→					Otherwise, insert at the beginning.
   409→				*/
   410→				if (sourceNextSettingNode) {
   411→					const targetNextSetting = findSettingNode(sourceNextSettingNode.setting!.key, targetTree);
   412→					if (targetNextSetting) {
   413→						const targetPreviousSetting = findPreviousSettingNode(targetTree.indexOf(targetNextSetting), targetTree);
   414→						const sourceCommentNodes = findNodesBetween(sourceTree, sourceTree[sourceNodeIndex], sourceNextSettingNode);
   415→						if (targetPreviousSetting) {
   416→							const targetCommentNodes = findNodesBetween(targetTree, targetPreviousSetting, targetNextSetting);
   417→							const targetCommentNode = findLastMatchingTargetCommentNode(sourceCommentNodes.reverse(), targetCommentNodes.reverse());
   418→							if (targetCommentNode) {
   419→								return { index: targetTree.indexOf(targetCommentNode), insertAfter: false }; /* Insert before comment */
   420→							} else {
   421→								return { index: targetTree.indexOf(targetPreviousSetting), insertAfter: true }; /* Insert after target previous setting */
   422→							}
   423→						} else {
   424→							const targetCommentNodes = findNodesBetween(targetTree, targetTree[0], targetNextSetting);
   425→							const targetCommentNode = findLastMatchingTargetCommentNode(sourceCommentNodes.reverse(), targetCommentNodes.reverse());
   426→							if (targetCommentNode) {
   427→								return { index: targetTree.indexOf(targetCommentNode), insertAfter: false }; /* Insert before comment */
   428→							} else {
   429→								return { index: 0, insertAfter: false }; /* Insert at the beginning */
   430→							}
   431→						}
   432→					}
   433→				}
   434→			}
   435→		}
   436→	}
   437→	/* Insert at the end */
   438→	return { index: targetTree.length - 1, insertAfter: true };
   439→}
   440→
   441→function insertAtLocation(content: string, key: string, value: any, location: InsertLocation, tree: INode[], formattingOptions: FormattingOptions): string {
   442→	let edits: Edit[];
   443→	/* Insert at the end */
   444→	if (location.index === -1) {
   445→		edits = setProperty(content, [key], value, formattingOptions);
   446→	} else {
   447→		edits = getEditToInsertAtLocation(content, key, value, location, tree, formattingOptions).map(edit => withFormatting(content, edit, formattingOptions)[0]);
   448→	}
   449→	return applyEdits(content, edits);
   450→}
   451→
   452→function getEditToInsertAtLocation(content: string, key: string, value: any, location: InsertLocation, tree: INode[], formattingOptions: FormattingOptions): Edit[] {
   453→	const newProperty = `${JSON.stringify(key)}: ${JSON.stringify(value)}`;
   454→	const eol = getEOL(formattingOptions, content);
   455→	const node = tree[location.index];
   456→
   457→	if (location.insertAfter) {
   458→
   459→		const edits: Edit[] = [];
   460→
   461→		/* Insert after a setting */
   462→		if (node.setting) {
   463→			edits.push({ offset: node.endOffset, length: 0, content: ',' + newProperty });
   464→		}
   465→
   466→		/* Insert after a comment */
   467→		else {
   468→
   469→			const nextSettingNode = findNextSettingNode(location.index, tree);
   470→			const previousSettingNode = findPreviousSettingNode(location.index, tree);
   471→			const previousSettingCommaOffset = previousSettingNode?.setting?.commaOffset;
   472→
   473→			/* If there is a previous setting and it does not has comma then add it */
   474→			if (previousSettingNode && previousSettingCommaOffset === undefined) {
   475→				edits.push({ offset: previousSettingNode.endOffset, length: 0, content: ',' });
   476→			}
   477→
   478→			const isPreviouisSettingIncludesComment = previousSettingCommaOffset !== undefined && previousSettingCommaOffset > node.endOffset;
   479→			edits.push({
   480→				offset: isPreviouisSettingIncludesComment ? previousSettingCommaOffset + 1 : node.endOffset,
   481→				length: 0,
   482→				content: nextSettingNode ? eol + newProperty + ',' : eol + newProperty
   483→			});
   484→		}
   485→
   486→
   487→		return edits;
   488→	}
   489→
   490→	else {
   491→
   492→		/* Insert before a setting */
   493→		if (node.setting) {
   494→			return [{ offset: node.startOffset, length: 0, content: newProperty + ',' }];
   495→		}
   496→
   497→		/* Insert before a comment */
   498→		const content = (tree[location.index - 1] && !tree[location.index - 1].setting /* previous node is comment */ ? eol : '')
   499→			+ newProperty
   500→			+ (findNextSettingNode(location.index, tree) ? ',' : '')
   501→			+ eol;
   502→		return [{ offset: node.startOffset, length: 0, content }];
   503→	}
   504→
   505→}
   506→
   507→function findSettingNode(key: string, tree: INode[]): INode | undefined {
   508→	return tree.filter(node => node.setting?.key === key)[0];
   509→}
   510→
   511→function findPreviousSettingNode(index: number, tree: INode[]): INode | undefined {
   512→	for (let i = index - 1; i >= 0; i--) {
   513→		if (tree[i].setting) {
   514→			return tree[i];
   515→		}
   516→	}
   517→	return undefined;
   518→}
   519→
   520→function findNextSettingNode(index: number, tree: INode[]): INode | undefined {
   521→	for (let i = index + 1; i < tree.length; i++) {
   522→		if (tree[i].setting) {
   523→			return tree[i];
   524→		}
   525→	}
   526→	return undefined;
   527→}
   528→
   529→function findNodesBetween(nodes: INode[], from: INode, till: INode): INode[] {
   530→	const fromIndex = nodes.indexOf(from);
   531→	const tillIndex = nodes.indexOf(till);
   532→	return nodes.filter((node, index) => fromIndex < index && index < tillIndex);
   533→}
   534→
   535→function findLastMatchingTargetCommentNode(sourceComments: INode[], targetComments: INode[]): INode | undefined {
   536→	if (sourceComments.length && targetComments.length) {
   537→		let index = 0;
   538→		for (; index < targetComments.length && index < sourceComments.length; index++) {
   539→			if (sourceComments[index].value !== targetComments[index].value) {
   540→				return targetComments[index - 1];
   541→			}
   542→		}
